// server.js
import express from 'express';
import cors from 'cors';
import helmet from 'helmet';
import morgan from 'morgan';
import rateLimit from 'express-rate-limit';

const app = express();

app.use(helmet());
app.use(cors({ origin: true, credentials: true }));
app.use(express.json({ limit: '2mb' }));
app.use(morgan('tiny'));

// Basic rate limiting (adjust for your environment)
const limiter = rateLimit({
  windowMs: 60 * 1000,
  max: 120,
});
app.use(limiter);

// Simple auth middleware (replace with your real auth)
function requireAuth(req, res, next) {
  const token = req.headers.authorization?.replace('Bearer ', '');
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  // TODO: verify JWT and set req.user
  req.user = { id: 'user_123', name: 'Reliable' };
  next();
}

// Idempotency middleware (for safe retries)
const idempotencyCache = new Map();
function requireIdempotencyKey(req, res, next) {
  const key = req.headers['idempotency-key'];
  if (!key) return res.status(400).json({ error: 'Missing Idempotency-Key header' });

  if (idempotencyCache.has(key)) {
    return res.json(idempotencyCache.get(key));
  }
  res.on('finish', () => {
    if (res.locals.responseBody) idempotencyCache.set(key, res.locals.responseBody);
  });
  next();
}

// Helper to send and capture response body for idempotency
function sendJson(res, body, status = 200) {
  res.locals.responseBody = body;
  return res.status(status).json(body);
}

app.get('/health', (_, res) => res.json({ ok: true }));

// Feature routers
import depositsRouter from './routes/deposits.js';
import billpayRouter from './routes/billpay.js';
import transfersRouter from './routes/transfers.js';

app.use('/api/deposits', requireAuth, depositsRouter);
app.use('/api/billpay', requireAuth, billpayRouter);
app.use('/api/transfers', requireAuth, transfersRouter);

const port = process.env.PORT || 4000;
app.listen(port, () => console.log(`API listening on :${port}`));




