// api/client.js
const API_BASE = 'http://localhost:4000/api';

async function request(path, method = 'GET', body, opts = {}) {
  const headers = {
    'Content-Type': 'application/json',
    Authorization: `Bearer YOUR_JWT_TOKEN`,
    ...(opts.idempotencyKey ? { 'Idempotency-Key': opts.idempotencyKey } : {}),
  };

  const res = await fetch(`${API_BASE}${path}`, {
    method,
    headers,
    body: body ? JSON.stringify(body) : undefined,
  });

  const data = await res.json();
  if (!res.ok) throw new Error(data.error || 'Request failed');
  return data;
}

export const api = {
  mobileDeposit: (payload) => request('/deposits/mobile', 'POST', payload),
  getDeposit: (id) => request(`/deposits/${id}`),

  createBillPayment: (payload, key) =>
    request('/billpay/payments', 'POST', payload, { idempotencyKey: key }),
  getBillPayment: (id) => request(`/billpay/payments/${id}`),

  createExternalTransfer: (payload, key) =>
    request('/transfers/external', 'POST', payload, { idempotencyKey: key }),
  getTransfer: (id) => request(`/transfers/${id}`),
};





