import React, { useState } from 'react';
import { View, Text, TextInput, Button, Image } from 'react-native';
import * as ImagePicker from 'expo-image-picker';
import { api } from '../api/client';

export default function MobileDepositScreen() {
  const [amount, setAmount] = useState('');
  const [front, setFront] = useState(null);
  const [back, setBack] = useState(null);
  const [status, setStatus] = useState('');

  const pick = async (setter) => {
    const res = await ImagePicker.launchCameraAsync({ base64: true, quality: 0.7 });
    if (!res.canceled) setter(res.assets[0]);
  };

  const submit = async () => {
    try {
      setStatus('Submitting...');
      const payload = {
        amount: Number(amount),
        frontImageBase64: front?.base64,
        backImageBase64: back?.base64,
      };
      const { deposit } = await api.mobileDeposit(payload);
      setStatus(`Submitted: ${deposit.id} (${deposit.status})`);
    } catch (e) {
      setStatus(`Error: ${e.message}`);
    }
  };

  return (
    <View style={{ padding: 16 }}>
      <Text>Mobile Deposit</Text>
      <TextInput
        placeholder="Amount (NGN)"
        keyboardType="numeric"
        value={amount}
        onChangeText={setAmount}
        style={{ borderWidth: 1, marginVertical: 8, padding: 8 }}
      />
      <Button title="Capture Front" onPress={() => pick(setFront)} />
      {front && <Image source={{ uri: front.uri }} style={{ height: 120, marginTop: 8 }} />}
      <Button title="Capture Back" onPress={() => pick(setBack)} />
      {back && <Image source={{ uri: back.uri }} style={{ height: 120, marginTop: 8 }} />}
      <Button title="Submit Deposit" onPress={submit} />
      <Text style={{ marginTop: 8 }}>{status}</Text>
    </View>
  );
}




