          {useFaceID ? (
             <div className="p-12 text-center flex flex-col items-center justify-center h-96 relative">
                <div className="w-48 h-48 rounded-full border-4 border-slate-200 dark:border-slate-700 overflow-hidden relative mb-6 shadow-inner bg-slate-100 dark:bg-slate-900 flex items-center justify-center">
