```tsx
import React, { useState, useEffect, useRef } from 'react';

interface LoginProps {
  onLogin: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [useFaceID, setUseFaceID] = useState(false);
  const [cameraError, setCameraError] = useState(false); // New state for error handling
  const [show2FA, setShow2FA] = useState(false);
  const [twoFACode, setTwoFACode] = useState('');

  const [username, setUsername] = useState('philip.mcmillan');
  const [password, setPassword] = useState('');
  const [errors, setErrors] = useState<{username?: string; password?: string; code?: string}>({});
  const videoRef = useRef<HTMLVideoElement>(null);

  const validateForm = () => {
    const newErrors: {username?: string; password?: string} = {};
    if (!username.trim()) newErrors.username = 'Username is required';
    if (!password) newErrors.password = 'Password is required';
    else if (password.length < 6) newErrors.password = 'Password must be at least 6 characters';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateForm()) return;

    setIsLoading(true);
    // Simulate network request
    setTimeout(() => {
      setIsLoading(false);

      // Check for 2FA Setting
      const is2FAEnabled = localStorage.getItem('is2FAEnabled') === 'true';
      if (is2FAEnabled) {
        setShow2FA(true);
      } else {
        onLogin();
      }
    }, 1500);
  };

  const handleVerify2FA = (e: React.FormEvent) => {
    e.preventDefault();
    if (twoFACode === '123456') {
      onLogin();
    } else {
      setErrors({ code: 'Invalid verification code (Hint: Use 123456)' });
    }
  };

  const handleFaceID = () => {
    setUseFaceID(true);
    setCameraError(false); // Reset error state on new attempt
  };

  useEffect(() => {
    let stream: MediaStream | null = null;
    let scanTimeout: number;

    if (useFaceID) {
      const startCamera = async () => {
        try {
          // Request camera access
          stream = await navigator.mediaDevices.getUserMedia({ video: true });
          if (videoRef.current) {
            videoRef.current.srcObject = stream;
            videoRef.current.play();
          }
          // Simulate scanning delay after camera is active
          scanTimeout = window.setTimeout(() => {
             onLogin();
          }, 2500);
        } catch (err) {
          console.error("Camera access failed or denied:", err);
          setCameraError(true); // Switch to simulation UI
          // Fallback simulation timer - allows login even if camera fails
          scanTimeout = window.setTimeout(() => {
             onLogin();
          }, 2000);
        }
      };

      startCamera();
    }

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
      clearTimeout(scanTimeout);
    };
  }, [useFaceID, onLogin]);

  // Enable Face ID Toggle State
  const [isFaceIDButtonVisible, setIsFaceIDButtonVisible] = useState(false);

  return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
      <div className="max-w-md w-full">
        {/* Brand Header */}
