import React, { useState, useEffect } from 'react';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import Receipt from './components/Receipt';
import Sidebar from './components/Sidebar';
import Cards from './components/Cards';
import Statements from './components/Statements';
import Settings from './components/Settings';
import VideoGenerator from './components/VideoGenerator';
import Home from './components/Home';
import Transfers from './components/Transfers';
import Support from './components/Support';
import { ViewState } from './types';

const App: React.FC = () => {
  // Simple state-based routing for this SPA
  const [viewState, setViewState] = useState<ViewState>({ view: 'HOME' });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Theme state
  const [isDarkMode, setIsDarkMode] = useState(() => {
    // Check local storage or system preference
    if (typeof window !== 'undefined') {
       return localStorage.getItem('theme') === 'dark' || 
              (!localStorage.getItem('theme') && window.matchMedia('(prefers-color-scheme: dark)').matches);
    }
    return false;
  });

  // Apply theme class to document
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  // Scroll to top on view change
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [viewState]);

  const toggleTheme = () => {
    setIsDarkMode(!isDarkMode);
  };

  const handleLogin = () => {
    setViewState({ view: 'DASHBOARD' });
  };

  const handleLogout = () => {
    setViewState({ view: 'HOME' });
    setIsMobileMenuOpen(false);
  };

  const handleNavigate = (view: ViewState['view']) => {
    // Sidebar navigation handler
    if (view === 'RECEIPT') return; 
    setViewState({ view: view as any });
    setIsMobileMenuOpen(false);
  };

  const navigateToReceipt = (transactionId: string) => {
    setViewState({ view: 'RECEIPT', transactionId });
  };

  // Conditional Rendering based on ViewState
  if (viewState.view === 'HOME') {
    return <Home onStart={() => setViewState({ view: 'LOGIN' })} />;
  }

  if (viewState.view === 'LOGIN') {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="flex min-h-screen bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 font-sans transition-colors duration-300">
      {/* Mobile Header */}
      <div className="lg:hidden fixed top-0 left-0 right-0 h-16 bg-white dark:bg-slate-800 border-b border-slate-200 dark:border-slate-700 z-50 flex items-center justify-between px-4 transition-colors duration-300">
        <div className="font-bold text-xl tracking-tight text-brand-900 dark:text-white flex items-center gap-2">
          <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 22h14"/><path d="M5 2h14"/><path d="M17 22v-4.172a2 2 0 0 0-.586-1.414L12 12l-4.414 4.414A2 2 0 0 0 7 17.828V22"/><path d="M7 2v4.172a2 2 0 0 0 .586 1.414L12 12l4.414-4.414A2 2 0 0 0 17 6.172V2"/></svg>
          </div>
          TrustBank
        </div>
        <button 
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          className="p-2 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-md"
        >
          {isMobileMenuOpen ? (
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          ) : (
             <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="3" y1="12" x2="21" y2="12"></line><line x1="3" y1="6" x2="21" y2="6"></line><line x1="3" y1="18" x2="21" y2="18"></line></svg>
          )}
        </button>
      </div>

      {/* Sidebar Navigation (Desktop + Mobile Drawer) */}
      <Sidebar 
        activeView={viewState.view} 
        isOpen={isMobileMenuOpen} 
        onNavigate={handleNavigate}
        onLogout={handleLogout}
        onCloseMobile={() => setIsMobileMenuOpen(false)}
        isDarkMode={isDarkMode}
        toggleTheme={toggleTheme}
      />

      {/* Main Content Area */}
      <main className="flex-1 lg:ml-64 p-4 lg:p-8 pt-20 lg:pt-8 overflow-y-auto">
        <div className="max-w-7xl mx-auto">
          {viewState.view === 'DASHBOARD' && (
            <Dashboard onNavigateReceipt={navigateToReceipt} isDarkMode={isDarkMode} />
          )}
          {viewState.view === 'RECEIPT' && (
            <Receipt 
              transactionId={(viewState as any).transactionId} 
              onBack={() => setViewState({ view: 'DASHBOARD' })} 
            />
          )}
          {viewState.view === 'CARDS' && <Cards />}
          {viewState.view === 'STATEMENTS' && <Statements />}
          {viewState.view === 'TRANSFERS' && <Transfers />}
          {viewState.view === 'SETTINGS' && <Settings />}
          {viewState.view === 'VIDEO_GEN' && <VideoGenerator />}
          {viewState.view === 'SUPPORT' && <Support />}
        </div>
      </main>
    </div>
  );
};

export default App;

