import React, { useState, useEffect, useRef } from 'react';

interface LoginProps {
  onLogin: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [useFaceID, setUseFaceID] = useState(false);
  const [show2FA, setShow2FA] = useState(false);
  const [twoFACode, setTwoFACode] = useState('');
  const [biometricsEnabled, setBiometricsEnabled] = useState(() => {
    return localStorage.getItem('biometricsEnabled') === 'true';
  });

  const [username, setUsername] = useState('philip.mcmillan');
  const [password, setPassword] = useState('');
  const [errors, setErrors] = useState<{username?: string; password?: string; code?: string; biometrics?: string}>({});
  const videoRef = useRef<HTMLVideoElement>(null);

  const toggleBiometrics = () => {
    const newVal = !biometricsEnabled;
    setBiometricsEnabled(newVal);
    localStorage.setItem('biometricsEnabled', String(newVal));
  };

  const validateForm = () => {
    const newErrors: {username?: string; password?: string} = {};
    if (!username.trim()) newErrors.username = 'Username is required';
    if (!password) newErrors.password = 'Password is required';
    else if (password.length < 6) newErrors.password = 'Password must be at least 6 characters';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateForm()) return;

    setIsLoading(true);
    // Simulate network request
    setTimeout(() => {
      setIsLoading(false);

      // Check for 2FA Setting
      const is2FAEnabled = localStorage.getItem('is2FAEnabled') === 'true';
      if (is2FAEnabled) {
        setShow2FA(true);
      } else {
        onLogin();
      }
    }, 1500);
  };

  const handleVerify2FA = (e: React.FormEvent) => {
    e.preventDefault();
    if (twoFACode === '123456') {
      onLogin();
    } else {
      setErrors({ code: 'Invalid verification code (Hint: Use 123456)' });
    }
  };

  const handleFaceID = () => {
    if (!biometricsEnabled) {
      setErrors({ biometrics: 'Biometric login is currently disabled. Please enable it below.' });
      return;
    }
    setErrors({});
    setUseFaceID(true);
  };

  useEffect(() => {
    let stream: MediaStream | null = null;
    let scanTimeout: number;

    if (useFaceID && biometricsEnabled) {
      const startCamera = async () => {
        try {
          stream = await navigator.mediaDevices.getUserMedia({ video: true });
          if (videoRef.current) {
            videoRef.current.srcObject = stream;
            videoRef.current.play();
          }
          // Simulate scanning delay after camera is active
          scanTimeout = window.setTimeout(() => {
             onLogin();
          }, 2500);
        } catch (err) {
          console.error("Camera access failed or denied:", err);
          setUseFaceID(false);
          setErrors({ biometrics: "Camera access was denied. Please use password login." });
        }
      };

      startCamera();
    }

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
      clearTimeout(scanTimeout);
    };
  }, [useFaceID, biometricsEnabled, onLogin]);

  return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
      <div className="max-w-md w-full">
        {/* Brand Header */}
        <div className="text-center mb-8">
           <div className="w-16 h-16 bg-gradient-to-br from-brand-400 to-brand-600 rounded-2xl flex items-center justify-center text-white shadow-2xl shadow-brand-500/30 mx-auto mb-4">
            <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 22h14"/><path d="M5 2h14"/><path d="M17 22v-4.172a2 2 0 0 0-.586-1.414L12 12l-4.414 4.414A2 2 0 0 0 7 17.828V22"/><path d="M7 2v4.172a2 2 0 0 0 .586 1.414L12 12l4.414-4.414A2 2 0 0 0 17 6.172V2"/></svg>
          </div>
          <h1 className="text-3xl font-bold text-white tracking-tight">TrustBank</h1>
          <p className="text-slate-400 mt-2">Secure access to your personal finance</p>
        </div>

        {/* Login Card */}
