        <div className="flex-1 h-12 bg-slate-200 dark:bg-slate-700 rounded-xl"></div>
      </div>
    </div>
  </div>
);

const Receipt: React.FC<ReceiptProps> = ({ transactionId, onBack }) => {
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const timer = setTimeout(() => setIsLoading(false), 1000);
    return () => clearTimeout(timer);
  }, []);

  const transaction = MOCK_TRANSACTIONS.find(t => t.id === transactionId);

  if (isLoading) return <ReceiptSkeleton />;

  if (!transaction) {
    return <div>Transaction not found</div>;
  }

  const isCredit = transaction.type === TransactionType.CREDIT;
  const isFailed = transaction.status === 'Failed';
  const dateObj = new Date(transaction.date);

  return (
    <div className="max-w-xl mx-auto animate-fade-in-up">
      <button 
        onClick={onBack}
        className="mb-6 flex items-center text-slate-500 dark:text-slate-400 hover:text-brand-600 dark:hover:text-brand-400 transition-colors font-medium"
      >
        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="mr-1"><path d="m15 18-6-6 6-6"/></svg>
        Back to Dashboard
      </button>

      <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-xl overflow-hidden relative transition-colors duration-300">
        {/* Receipt Cut Effect (Visual Decoration) */}
