              {isFailed ? (
                 <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>
              ) : isCredit ? (
                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="23 6 13.5 15.5 8.5 10.5 1 18"></polyline><polyline points="17 6 23 6 23 12"></polyline></svg>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><path d="m9 12 2 2 4-4"/></svg>
              )}
           </div>
           <h2 className={`text-3xl font-bold mb-1 ${isFailed ? 'text-red-600 dark:text-red-400' : 'text-slate-900 dark:text-white'}`}>
             {isCredit ? '+' : '-'}${transaction.amount.toFixed(2)}
           </h2>
           <p className="text-slate-500 dark:text-slate-400">{transaction.merchant}</p>
           <span className={`inline-block mt-3 px-3 py-1 rounded-full text-xs font-semibold ${
