import React, { useState, useEffect, useRef } from 'react';

interface LoginProps {
  onLogin: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [useFaceID, setUseFaceID] = useState(false);
  const [show2FA, setShow2FA] = useState(false);
  const [twoFACode, setTwoFACode] = useState('');
  const [biometricsEnabled, setBiometricsEnabled] = useState(() => {
    return localStorage.getItem('biometricsEnabled') === 'true';
  });

  const [username, setUsername] = useState('philip.mcmillan');
  const [password, setPassword] = useState('');
  const [errors, setErrors] = useState<{username?: string; password?: string; code?: string; biometrics?: string}>({});
  const videoRef = useRef<HTMLVideoElement>(null);

  const toggleBiometrics = () => {
    const newVal = !biometricsEnabled;
    setBiometricsEnabled(newVal);
    localStorage.setItem('biometricsEnabled', String(newVal));
  };

  const validateForm = () => {
    const newErrors: {username?: string; password?: string} = {};
    if (!username.trim()) newErrors.username = 'Username is required';
    if (!password) newErrors.password = 'Password is required';
    else if (password.length < 6) newErrors.password = 'Password must be at least 6 characters';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateForm()) return;

    setIsLoading(true);
    setTimeout(() => {
      setIsLoading(false);
      const is2FAEnabled = localStorage.getItem('is2FAEnabled') === 'true';
      if (is2FAEnabled) {
        setShow2FA(true);
      } else {
        onLogin();
      }
    }, 1500);
  };

  const handleVerify2FA = (e: React.FormEvent) => {
    e.preventDefault();
    if (twoFACode === '123456') {
      onLogin();
    } else {
      setErrors({ code: 'Invalid verification code (Hint: Use 123456)' });
    }
  };

  const handleFaceID = () => {
    if (!biometricsEnabled) {
      setErrors({ biometrics: 'Biometric login is currently disabled. Please enable it below.' });
      return;
    }
    setErrors({});
    setUseFaceID(true);
  };

  useEffect(() => {
    let stream: MediaStream | null = null;
    let scanTimeout: number;

    if (useFaceID && biometricsEnabled) {
      const startCamera = async () => {
        try {
          stream = await navigator.mediaDevices.getUserMedia({ video: true });
          if (videoRef.current) {
            videoRef.current.srcObject = stream;
            videoRef.current.play();
          }
          scanTimeout = window.setTimeout(() => {
             onLogin();
          }, 2500);
        } catch (err) {
          console.error("Camera access failed:", err);
          setUseFaceID(false);
          setErrors({ biometrics: "Camera access denied. Please use password." });
        }
      };

      startCamera();
    }

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
      clearTimeout(scanTimeout);
    };
  }, [useFaceID, biometricsEnabled, onLogin]);

  return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4 sm:p-6 overflow-y-auto">
      <div className="max-w-md w-full py-8">
        {/* Brand Header */}
        <div className="text-center mb-6 sm:mb-10">
           <div className="w-12 h-12 sm:w-16 sm:h-16 bg-gradient-to-br from-brand-400 to-brand-600 rounded-2xl flex items-center justify-center text-white shadow-2xl shadow-brand-500/30 mx-auto mb-4 animate-fade-in-down">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 22h14"/><path d="M5 2h14"/><path d="M17 22v-4.172a2 2 0 0 0-.586-1.414L12 12l-4.414 4.414A2 2 0 0 0 7 17.828V22"/><path d="M7 2v4.172a2 2 0 0 0 .586 1.414L12 12l4.414-4.414A2 2 0 0 0 17 6.172V2"/></svg>
          </div>
          <h1 className="text-2xl sm:text-3xl font-black text-white tracking-tight">TrustBank</h1>
          <p className="text-slate-500 mt-2 text-sm sm:text-base">Secure financial gateway</p>
        </div>

        {/* Login Card */}
        <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-2xl overflow-hidden relative transition-all duration-300">

          {useFaceID ? (
             <div className="p-8 sm:p-12 text-center flex flex-col items-center justify-center min-h-[380px] sm:min-h-[400px] relative animate-fade-in">
                <div className="w-40 h-40 sm:w-48 sm:h-48 rounded-full border-4 border-slate-100 dark:border-slate-700 overflow-hidden relative mb-8 shadow-inner bg-slate-50 dark:bg-slate-900">
                  <video 
                    ref={videoRef} 
                    className="w-full h-full object-cover transform scale-x-[-1]" 
                    playsInline 
                    muted 
                  />
                  <div className="absolute inset-0 bg-brand-500/10 animate-pulse"></div>
                  <div className="absolute top-0 left-0 w-full h-1 bg-brand-400 shadow-[0_0_15px_rgba(56,189,248,0.8)] animate-[scan_2s_ease-in-out_infinite]"></div>
                </div>
                <h3 className="text-lg sm:text-xl font-bold text-slate-900 dark:text-white">Verifying Identity</h3>
                <p className="text-slate-400 text-xs sm:text-sm mt-2">Center your face in the frame</p>
                <button 
                  onClick={() => setUseFaceID(false)}
                  className="mt-6 text-sm font-bold text-brand-600 dark:text-brand-400 hover:text-brand-700 transition-colors"
                >
                  Switch to Password
                </button>
             </div>
          ) : show2FA ? (
            <div className="p-6 sm:p-10 animate-fade-in">
              <h2 className="text-xl sm:text-2xl font-bold text-slate-900 dark:text-white mb-2">Verification</h2>
              <p className="text-slate-500 dark:text-slate-400 mb-8 text-sm">Enter the 6-digit code sent to your device.</p>

              <form onSubmit={handleVerify2FA} className="space-y-6">
                <div>
                  <input 
                    type="text" 
                    value={twoFACode}
                    onChange={(e) => setTwoFACode(e.target.value.replace(/[^0-9]/g, '').slice(0, 6))}
                    className={`w-full px-4 py-4 rounded-2xl border ${errors.code ? 'border-red-500 ring-4 ring-red-50' : 'border-slate-200 dark:border-slate-600 focus:ring-4 focus:ring-brand-50'} bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none transition-all text-center tracking-[1em] text-2xl font-black font-mono`}
                    placeholder="000000"
                    autoFocus
                  />
                  {errors.code && <p className="text-red-500 text-xs mt-2 text-center font-bold">{errors.code}</p>}
                </div>

                <button 
                  type="submit" 
                  className="w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-4 rounded-2xl shadow-xl shadow-brand-500/30 transition-all transform active:scale-95 flex justify-center items-center"
                >
                  Verify Identity
                </button>
              </form>
              <div className="mt-8 text-center">
                 <button onClick={() => { setShow2FA(false); setTwoFACode(''); setErrors({}); }} className="text-sm font-bold text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors">
                    Back to Login
                 </button>
              </div>
            </div>
          ) : (
            <div className="p-6 sm:p-10 animate-fade-in">
              <div className="mb-8">
                <h2 className="text-2xl font-black text-slate-900 dark:text-white mb-1">Sign In</h2>
                <p className="text-sm text-slate-500">Access your secure dashboard</p>
              </div>

              {errors.biometrics && (
                 <div className="mb-6 p-4 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 text-xs sm:text-sm rounded-xl flex items-center gap-3 border border-red-100 dark:border-red-900/30">
                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="shrink-0"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
                    {errors.biometrics}
                 </div>
              )}

              <form onSubmit={handleLogin} className="space-y-5">
                <div>
                  <label className="block text-xs font-black uppercase tracking-widest text-slate-400 mb-2">Username</label>
                  <input 
                    type="text" 
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    className={`w-full px-4 py-3.5 rounded-xl border ${errors.username ? 'border-red-500' : 'border-slate-200 dark:border-slate-600 focus:ring-4 focus:ring-brand-50'} bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none transition-all text-sm sm:text-base font-medium`}
                    placeholder="e.g. philip.mcmillan"
                  />
                  {errors.username && <p className="text-red-500 text-[10px] mt-1 font-bold">{errors.username}</p>}
                </div>

                <div>
                  <div className="flex justify-between mb-2">
                    <label className="block text-xs font-black uppercase tracking-widest text-slate-400">Password</label>
                    <a href="#" className="text-xs font-bold text-brand-600 hover:text-brand-700">Forgot?</a>
                  </div>
                  <input 
                    type="password" 
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className={`w-full px-4 py-3.5 rounded-xl border ${errors.password ? 'border-red-500' : 'border-slate-200 dark:border-slate-600 focus:ring-4 focus:ring-brand-50'} bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none transition-all text-sm sm:text-base font-medium`}
                    placeholder="••••••••"
                  />
                   {errors.password && <p className="text-red-500 text-[10px] mt-1 font-bold">{errors.password}</p>}
                </div>

                <button 
                  type="submit" 
                  disabled={isLoading}
                  className="w-full bg-brand-600 hover:bg-brand-700 text-white font-black py-4 rounded-2xl shadow-xl shadow-brand-500/30 transition-all transform active:scale-[0.98] disabled:opacity-70 disabled:cursor-not-allowed flex justify-center items-center"
                >
                  {isLoading ? (
                    <div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin"></div>
                  ) : 'Login to Account'}
                </button>
              </form>

              <div className="mt-8 flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-900/50 rounded-2xl border border-slate-100 dark:border-slate-700">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-full bg-white dark:bg-slate-800 flex items-center justify-center shadow-sm">
                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="text-slate-500"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>
                  </div>
                  <span className="text-xs sm:text-sm font-bold text-slate-700 dark:text-slate-300">Biometric Sign-in</span>
                </div>
                <button 
                  onClick={toggleBiometrics}
                  className={`w-10 h-6 rounded-full relative transition-all ${biometricsEnabled ? 'bg-brand-600' : 'bg-slate-300 dark:bg-slate-700'}`}
                >
                  <div className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full shadow-md transition-transform duration-200 ${biometricsEnabled ? 'translate-x-4' : 'translate-x-0'}`}></div>
                </button>
              </div>

              <div className="mt-8">
                <div className="relative">
                  <div className="absolute inset-0 flex items-center">
                    <div className="w-full border-t border-slate-100 dark:border-slate-700"></div>
                  </div>
                  <div className="relative flex justify-center text-[10px] uppercase font-black tracking-widest">
                    <span className="px-3 bg-white dark:bg-slate-800 text-slate-400">Quick Access</span>
                  </div>
                </div>

                <button 
                  onClick={handleFaceID}
                  disabled={!biometricsEnabled}
                  className={`mt-6 w-full font-black py-4 rounded-2xl border transition-all flex items-center justify-center gap-3 active:scale-[0.98] ${biometricsEnabled ? 'bg-white dark:bg-slate-700 text-slate-800 dark:text-white border-slate-200 dark:border-slate-600 hover:bg-slate-50 dark:hover:bg-slate-600 shadow-sm' : 'bg-slate-50 dark:bg-slate-800/50 text-slate-300 border-slate-100 dark:border-slate-800 cursor-not-allowed'}`}
                >
