                    <div className="flex justify-between items-center py-4 border-b border-slate-100 dark:border-slate-800">
                      <span className="text-slate-400 text-xs font-black uppercase tracking-widest">Amount</span>
                      <span className="font-black text-2xl text-slate-900 dark:text-white">${parseFloat(amount || '0').toLocaleString('en-US', { minimumFractionDigits: 2 })}</span>
                    </div>
                    <div className="flex justify-between items-center pt-2 text-[10px] text-brand-600 dark:text-brand-400 font-black uppercase tracking-widest">
                      <span>Delivery Method</span>
                      <span className="px-2 py-0.5 bg-brand-100 dark:bg-brand-900/30 rounded">Instant</span>
                    </div>
                  </div>
                  <div className="flex flex-col sm:flex-row gap-3">
                    <button type="button" onClick={() => setStep(2)} className="order-2 sm:order-1 flex-1 py-4 bg-slate-100 dark:bg-slate-900 text-slate-600 dark:text-slate-400 rounded-2xl font-black transition-colors hover:bg-slate-200 dark:hover:bg-slate-800">Modify</button>
                    <button 
                      type="submit" 
                      disabled={isProcessing}
                      className="order-1 sm:order-2 flex-1 py-4 bg-brand-600 text-white rounded-2xl font-black shadow-xl shadow-brand-500/30 flex items-center justify-center gap-3 active:scale-95 transition-transform"
                    >
                      {isProcessing ? <div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Confirm & Transfer'}
                    </button>
                  </div>
                </div>
              )}
            </form>
          </div>
        </div>

        {/* Sidebar Linked Accounts - stacks on mobile */}
        <div className="space-y-6">
          <h3 className="text-sm font-black uppercase tracking-widest text-slate-400 px-1">Frequent Links</h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-1 gap-4">
            {linkedAccounts.map(acc => (
              <button key={acc.id} className="p-5 bg-white dark:bg-slate-800 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-700 flex items-center justify-between hover:bg-slate-50 dark:hover:bg-slate-700 transition-all active:scale-[0.98] group">
                <div className="flex items-center gap-4 min-w-0">
                  <div className={`w-3 h-3 rounded-full shrink-0 ${acc.color} group-hover:scale-125 transition-transform`}></div>
                  <div className="text-left min-w-0">
                    <div className="text-sm font-black text-slate-900 dark:text-white truncate">{acc.name}</div>
                    <div className="text-[10px] font-bold text-slate-400 mt-0.5 tracking-tight">${acc.balance.toLocaleString()} available</div>
                  </div>
                </div>
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="text-slate-200 group-hover:text-brand-500 transition-colors shrink-0 ml-2"><polyline points="9 18 15 12 9 6"/></svg>
              </button>
            ))}
            <button className="p-5 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl flex items-center justify-center gap-2 text-slate-400 hover:text-brand-600 hover:border-brand-600 hover:bg-brand-50/10 transition-all text-xs font-black uppercase tracking-wider">
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><path d="M12 8v8"/><path d="M8 12h8"/></svg>
              Add Connection
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Transfers;

import React, { useState, useEffect } from 'react';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import Receipt from './components/Receipt';
import Sidebar from './components/Sidebar';
import Cards from './components/Cards';
import Statements from './components/Statements';
import Settings from './components/Settings';
import VideoGenerator from './components/VideoGenerator';
import Home from './components/Home';
import Transfers from './components/Transfers';
import Support from './components/Support';
import { ViewState } from './types';

const App: React.FC = () => {
  const [viewState, setViewState] = useState<ViewState>({ view: 'HOME' });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
       return localStorage.getItem('theme') === 'dark' || 
              (!localStorage.getItem('theme') && window.matchMedia('(prefers-color-scheme: dark)').matches);
    }
    return false;
  });

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [viewState]);

  const toggleTheme = () => {
    setIsDarkMode(!isDarkMode);
  };

  const handleLogin = () => {
    setViewState({ view: 'DASHBOARD' });
  };

  const handleLogout = () => {
    setViewState({ view: 'HOME' });
    setIsMobileMenuOpen(false);
  };

  const handleNavigate = (view: ViewState['view']) => {
    if (view === 'RECEIPT') return; 
    setViewState({ view: view as any });
    setIsMobileMenuOpen(false);
  };

  const navigateToReceipt = (transactionId: string) => {
    setViewState({ view: 'RECEIPT', transactionId });
  };

  if (viewState.view === 'HOME') {
    return <Home onStart={() => setViewState({ view: 'LOGIN' })} />;
  }

  if (viewState.view === 'LOGIN') {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="flex min-h-screen bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 font-sans transition-colors duration-300 overflow-x-hidden">
      {/* Mobile Header - Fixed Height 16 (4rem / 64px) */}
      <div className="lg:hidden fixed top-0 left-0 right-0 h-16 bg-white/90 dark:bg-slate-800/90 backdrop-blur-md border-b border-slate-100 dark:border-slate-700 z-50 flex items-center justify-between px-4 transition-colors duration-300">
        <div className="font-black text-lg tracking-tight text-slate-900 dark:text-white flex items-center gap-2">
          <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white shadow-lg shadow-brand-500/20">
            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M5 22h14"/><path d="M5 2h14"/><path d="M17 22v-4.172a2 2 0 0 0-.586-1.414L12 12l-4.414 4.414A2 2 0 0 0 7 17.828V22"/><path d="M7 2v4.172a2 2 0 0 0 .586 1.414L12 12l4.414-4.414A2 2 0 0 0 17 6.172V2"/></svg>
          </div>
          TrustBank
        </div>
        <button 
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          className="p-2 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-xl transition-colors"
          aria-label="Toggle Menu"
        >
          {isMobileMenuOpen ? (
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          ) : (
             <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="3" y1="12" x2="21" y2="12"></line><line x1="3" y1="6" x2="21" y2="6"></line><line x1="3" y1="18" x2="21" y2="18"></line></svg>
          )}
        </button>
      </div>

      <Sidebar 
        activeView={viewState.view} 
        isOpen={isMobileMenuOpen} 
        onNavigate={handleNavigate}
        onLogout={handleLogout}
        onCloseMobile={() => setIsMobileMenuOpen(false)}
        isDarkMode={isDarkMode}
        toggleTheme={toggleTheme}
      />

      {/* Main Content Area - Optimized Padding for Mobile */}
      <main className="flex-1 lg:ml-64 p-4 sm:p-6 lg:p-8 pt-20 sm:pt-24 lg:pt-8 min-h-screen">
        <div className="max-w-7xl mx-auto h-full">
          {viewState.view === 'DASHBOARD' && (
            <Dashboard onNavigateReceipt={navigateToReceipt} isDarkMode={isDarkMode} />
          )}
          {viewState.view === 'RECEIPT' && (
            <Receipt 
              transactionId={(viewState as any).transactionId} 
              onBack={() => setViewState({ view: 'DASHBOARD' })} 
            />
          )}
          {viewState.view === 'CARDS' && <Cards />}
          {viewState.view === 'STATEMENTS' && <Statements />}
          {viewState.view === 'TRANSFERS' && <Transfers />}
          {viewState.view === 'SETTINGS' && <Settings />}
          {viewState.view === 'VIDEO_GEN' && <VideoGenerator />}
          {viewState.view === 'SUPPORT' && <Support />}
        </div>
      </main>
    </div>
  );
};

export default App;
